# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ElasticsearchException
import os

app = Flask(__name__)

ES_URL = os.getenv("ELASTICSEARCH_URL", "http://localhost:9200")
ES_INDEX = os.getenv("ELASTICSEARCH_INDEX", "products")

es = Elasticsearch(
    ES_URL,
    request_timeout=2,
    max_retries=3,
    retry_on_timeout=True,
    verify_certs=os.getenv("ELASTICSEARCH_VERIFY_CERTS", "true").lower() == "true",
)

@app.get("/api/search")
def search_products():
    q = request.args.get("q", "").strip()
    if not q:
        return jsonify({"error": "missing required query parameter: q"}), 400

    try:
        response = es.search(
            index=ES_INDEX,
            size=min(int(request.args.get("limit", 20)), 100),
            track_total_hits=False,
            query={
                "bool": {
                    "must": [
                        {
                            "multi_match": {
                                "query": q,
                                "fields": ["name^3", "description", "brand^2", "category"],
                                "type": "best_fields",
                                "fuzziness": "AUTO",
                            }
                        }
                    ],
                    "filter": [],
                }
            },
            sort=["_score", {"popularity": "desc"}, {"_id": "asc"}],
            _source=["id", "name", "brand", "category", "price", "image_url", "availability"],
        )
    except ElasticsearchException:
        return jsonify({"error": "search service unavailable"}), 503

    hits = response.get("hits", {}).get("hits", [])
    products = []
    for hit in hits:
        src = hit.get("_source", {})
        src["score"] = hit.get("_score")
        products.append(src)

    return jsonify({"query": q, "count": len(products), "products": products}), 200

@app.get("/health")
def health():
    return jsonify({"status": "ok"}), 200

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", 5000)))